import React from "react";

export type ZentradeAiIconProps = {
  size?: number | string;
  className?: string;
  title?: string;
  alt?: string;
};

export default function ZentradeAiIcon({
  size = 48,
  className = "",
  title = "zentrade-ai",
  alt = "zentrade-ai",
}: ZentradeAiIconProps) {
  return (
    <img
      src="data:image/svg+xml;base64,"
      width={size}
      height={size}
      className={className}
      title={title}
      alt={alt}
      style={{
        width: size,
        height: size,
        objectFit: "contain",
        display: "inline-block",
      }}
      loading="lazy"
      decoding="async"
    />
  );
}
